const loginForm=document.getElementById("login-form"),loginButton=document.getElementById("login-button"),loginMessage=document.getElementById("login-message"),loginInput=document.getElementById("id_magalu"),STORAGE_KEY="magalu_system_user",existingSession=localStorage.getItem(STORAGE_KEY);function setMessage(e,t){loginMessage.textContent=e,loginMessage.className=`form-message ${t}`}existingSession&&window.location.replace(new URL("../teste/",window.location.href)),loginForm.addEventListener("submit",async e=>{e.preventDefault();const t=loginInput.value.trim();if(t){loginButton.disabled=!0,loginButton.textContent="Entrando...",setMessage("","");try{const e=await fetch(window.magaluApi.buildApiUrl("/api/auth/login"),window.magaluApi.withApiDefaults({method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({id_magalu:t})})),o=await e.json();if(!e.ok)throw new Error(o.error||"Nao foi possivel efetuar o login.");localStorage.setItem(STORAGE_KEY,JSON.stringify(o.user)),setMessage("Login efetuado. Redirecionando...","success"),window.setTimeout(()=>{window.location.href=new URL("../teste/",window.location.href)},400)}catch(e){setMessage(e.message,"error")}finally{loginButton.disabled=!1,loginButton.textContent="Entrar"}}else setMessage("Informe o ID Magalu para entrar.","error")});